const items = $input.all();
const summary = items[0]?.json ?? [];
const alerts  = items[1]?.json ?? [];

const summaryArr = Array.isArray(summary) ? summary : [summary];
const alertsArr  = Array.isArray(alerts)  ? alerts  : [alerts];

const semanaStr = new Date().toLocaleDateString('es-CO', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

const kpiBlock = summaryArr.map(a =>
  `• ${a.area}: ${a.pct_real}% real vs ${a.pct_planificado}% planificado | ${a.completadas}/${a.total_tareas} tareas | ${a.bloqueadas} bloqueadas | ${a.vencidas} vencidas | semáforo: ${a.semaforo}`
).join('\n');

const alertBlock = alertsArr.length === 0 ? 'Sin alertas críticas.' :
  alertsArr.slice(0, 10).map(a => `• [${a.tipo}] ${a.descripcion}`).join('\n');

const userPrompt = `Hoy es ${semanaStr}. Genera un reporte ejecutivo semanal para Clementino (CEO de La Falla DF), empresa de producción audiovisual y consultoría en Colombia.\n\nKPIs por área:\n${kpiBlock}\n\nAlertas:\n${alertBlock}\n\nEl reporte debe:\n1. Empezar con un saludo breve\n2. Destacar lo más importante (logros + riesgos)\n3. Dar 2-3 recomendaciones concretas de acción\n4. Cerrar con motivación\n5. Ser máximo 250 palabras\n6. Usar emojis con moderación`;

return [{ json: { userPrompt } }];

const response = $input.item.json;
const text = response.choices?.[0]?.message?.content ?? 'Sin respuesta de IA';
const fecha = new Date().toLocaleDateString('es-CO', {day:'numeric', month:'long', year:'numeric'});
return { json: { content: `📊 *Reporte Semanal — ${fecha}*\n\n${text}` } };
